// BROKEN — the #1 real-world API vulnerability.
@GetMapping("/orders/{id}")
public Order getOrder(@PathVariable Long id) {
  return orderRepository.findById(id).orElseThrow();
  // Attacker: 'let me try /orders/1, /orders/2, /orders/3...'
  // -> reads EVERY user's orders. This is IDOR / BOLA.
}

// FIXED — always check ownership.
@GetMapping("/orders/{id}")
@PreAuthorize("@ownershipChecker.canAccessOrder(#id, authentication)")
public Order getOrder(@PathVariable Long id) {
  return orderRepository.findById(id).orElseThrow();
}

@Component
class OwnershipChecker {
  public boolean canAccessOrder(Long orderId, Authentication auth) {
    var userId = ((Jwt) auth.getPrincipal()).getSubject();
    return orderRepository.existsByIdAndUserId(orderId, userId);
    // OR the query is scoped by userId from the start:
    //   orderRepository.findByIdAndUserId(orderId, userId)
  }
}

