// BROKEN — user submits { "name": "Ada", "isAdmin": true } -> they promote themselves!
@PatchMapping("/users/{id}")
public User update(@PathVariable Long id, @RequestBody User user) {
  var existing = userRepo.findById(id).orElseThrow();
  BeanUtils.copyProperties(user, existing);   // copies EVERY field including isAdmin
  return userRepo.save(existing);
}

// FIXED — use a DTO with ONLY the fields users may update.
public record UpdateProfileRequest(
    @NotBlank String name,
    @Email String email,
    @Size(max = 500) String bio
    // Deliberately: NO isAdmin, NO roles, NO id, NO createdAt.
) {}

@PatchMapping("/users/{id}")
public UserDto update(@PathVariable Long id, @Valid @RequestBody UpdateProfileRequest req) {
  var existing = userRepo.findByIdAndUserId(id, currentUserId()).orElseThrow();
  existing.setName(req.name());
  existing.setEmail(req.email());
  existing.setBio(req.bio());
  return UserDto.from(userRepo.save(existing));
}

// Rule: NEVER accept an entity type directly from the HTTP body.
// ALWAYS use a request DTO that exposes only user-editable fields.
// This one habit prevents most mass-assignment CVEs.

// Bucket4j — token-bucket rate limiter, integrates with Spring.
// implementation 'com.bucket4j:bucket4j_jcache:8.10.1'

@Component
public class RateLimitFilter extends OncePerRequestFilter {
  private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();

  @Override
  protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res, FilterChain chain)
      throws ServletException, IOException {
    var key = clientKey(req);   // API key, or IP, or user ID
    var bucket = buckets.computeIfAbsent(key, this::newBucket);

    if (bucket.tryConsume(1)) {
      chain.doFilter(req, res);
    } else {
      res.setStatus(429);
      res.setHeader("Retry-After", "60");
      res.getWriter().write("{\"error\":\"Rate limit exceeded\"}");
    }
  }

  private Bucket newBucket(String key) {
    return Bucket.builder()
        .addLimit(Bandwidth.builder().capacity(100).refillGreedy(100, Duration.ofMinutes(1)).build())
        .build();
  }

  private String clientKey(HttpServletRequest req) {
    // Prefer authenticated user ID > API key > IP
    var auth = SecurityContextHolder.getContext().getAuthentication();
    if (auth != null && auth.isAuthenticated()) return "user:" + auth.getName();
    var apiKey = req.getHeader("X-Api-Key");
    if (apiKey != null) return "key:" + apiKey;
    return "ip:" + req.getRemoteAddr();
  }
}

